import zipfile
from pathlib import Path

def extract_zip(zip_file_path: str) -> None:
    if not (Path(zip_file_path).suffix == '.zip'):
        raise ValueError("Invalid file type. Expected .zip.")

    try:
        with zipfile.ZipFile(zip_file_path, 'r') as z:
            z.extractall()
    except Exception as e:
        print(f"Error occurred while extracting zip: {e}")

