import os

def open_config(base_dir, path_component):
    allowed_paths = [".ini", ".yaml", ".json"]

    if not all(os.path.isdir(os.path.join(base_dir, p)) or (os.path.isfile(os.path.join(base_dir, p)) and p.split('.')[-1] in allowed_paths) for p in path_component.split('/')):
        raise ValueError("Invalid path components.")

    config_path = os.path.join(base_dir, path_component)
    with open(config_path, "r") as f:
        return f.read()
